    void (^toggleNotificationBlock)(BOOL) = ^(BOOL enable) {
        [WBNetworkManager.defaultManager connectNotification:vapp.bundleId isOn:!enable callback:^(id _Nullable json, NSError *_Nullable error) {
            dispatch_async(dispatch_get_main_queue(), ^{
                if (error) {
                    vapp.featureStatusInfo.isNotificationSwitchOn = !enable;
                    [WBVAppManager.sharedManager saveBackgroundSetting:!enable forVApp:vapp];
                    [SVProgressHUD showErrorWithStatus:error.localizedDescription];
                    return;
                }

                /**
                 canOn值说明：
                    0：服务器决定关；
                    1：服务器决定开；
                    2：服务器决定开并弹不稳定提示弹窗（app下架）;
                 */
                id canOn = json[@"canOn"];  // 服务器决定的开关结果
                id tip = json[@"tip"];  // 开关结果提示语
                id route = json[@"route"];  // 开关操作后执行的路由
                if (!canOn || [canOn isKindOfClass:[NSNull class]]) return;
                NSInteger canOnNumber = [(NSNumber *)canOn integerValue];
                vapp.featureStatusInfo.isNotificationSwitchOn = (canOnNumber != 0);
                [WBVAppManager.sharedManager saveBackgroundSetting:vapp.featureStatusInfo.isNotificationSwitchOn forVApp:vapp];
                if (setSwitch) setSwitch(vapp.featureStatusInfo.isNotificationSwitchOn, YES);
                if (enable && vapp.featureStatusInfo.isNotificationSwitchOn) {
                    [self consumeUsageOnceForBenefitBit:WBUserBenefitNotification];
                }

                if (enable) {   // 开启
                    if (canOnNumber == 2) {
                        UIAlertController *alertVC = [UIAlertController alertControllerWithTitle:@"温馨提示" message:@"当前版本【消息推送】尚不稳定\n如需帮助，请联系客服咨询" preferredStyle:UIAlertControllerStyleAlert];
                        [alertVC addAction:[UIAlertAction actionWithTitle:@"确定" style:UIAlertActionStyleDefault handler:nil]];
                        UIViewController *vc = presenter ?: [WBAppManager getUIApplicationRootViewController];
                        [vc presentViewController:alertVC animated:YES completion:nil];
                    } else if (tip && ![tip isKindOfClass:[NSNull class]]) {
                        NSString *trimmedTip = [[tip stringValue] stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceCharacterSet]];
                        if (trimmedTip.length > 0) {
                            if (canOnNumber == 1) [SVProgressHUD showSuccessWithStatus:trimmedTip]; else [SVProgressHUD showErrorWithStatus:trimmedTip];
                        }
                    }
                } else if (tip && ![tip isKindOfClass:[NSNull class]]) {
                    NSString *trimmedTip = [[tip stringValue] stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceCharacterSet]];
                    if (trimmedTip.length > 0) {
                        if (canOnNumber == 0) [SVProgressHUD showSuccessWithStatus:trimmedTip]; else [SVProgressHUD showErrorWithStatus:trimmedTip];
                    }
                }

                if (route && ![route isKindOfClass:[NSNull class]] && [route isKindOfClass:[NSString class]]) {
                    NSURL *routeUrl = [NSURL URLWithString:(NSString *)route];
                    [[WBRouteManager sharedManager] performRoute:routeUrl sourceInterface:@"user/notifyConnect"];
                }
            });
        }];
    };

