    NSString *hashedKey = [WBUtility getCodeNameSaltedSha1Hash:key];
    NSMutableDictionary *toStore = [NSMutableDictionary dictionaryWithCapacity:BenefitTrialUsageTimes.count];
    [BenefitTrialUsageTimes enumerateKeysAndObjectsUsingBlock:^(id k, id obj, BOOL *stop) {
        NSString *stringKey = [k isKindOfClass:NSString.class] ? k : [[k description] copy];
        NSNumber *num = [obj isKindOfClass:NSNumber.class] ? obj : @([[obj description] integerValue]);
        if (stringKey && num) {
            NSInteger iv = [num integerValue];
            if (iv < 0) iv = 0;
            toStore[stringKey] = @(iv);
